import React, { useState, useEffect } from 'react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import ProductCard from '../components/ProductCard';
import { products, categories } from '../api';
import { useApp } from '../context/AppContext';
import { 
  ArrowRight, 
  Smartphone, 
  Shirt, 
  ShoppingBag, 
  Watch, 
  Home as HomeIcon,
  Star,
  Quote,
  Search
} from 'lucide-react';

const Home = () => {
  const { t } = useApp();
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();
  const [productsList, setProductsList] = useState([]);
  const [brands, setBrands] = useState([]);
  const [selectedBrand, setSelectedBrand] = useState(searchParams.get('brand') || '');
  const [searchQuery, setSearchQuery] = useState(searchParams.get('name') || '');

  // Mock categories for the redesign
  const categoryTiles = [
    { name: t('cat_electronics'), icon: <Smartphone size={32} />, color: '#EFF6FF' },
    { name: t('cat_clothing'), icon: <Shirt size={32} />, color: '#FEF3C7' },
    { name: t('cat_shoes'), icon: <ShoppingBag size={32} />, color: '#ECFDF5' },
    { name: t('cat_accessories'), icon: <Watch size={32} />, color: '#F5F3FF' },
    { name: t('cat_home'), icon: <HomeIcon size={32} />, color: '#FFF1F2' },
  ];

  // Mock reviews
  const reviews = [
    { name: 'Azizbek K.', role: 'Dizayner', text: 'Juda mazmunli va sifatli mahsulotlar. Xizmat ko‘rsatish ham a‘lo darajada!', rating: 5, img: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100' },
    { name: 'Malika R.', role: 'Tadbirkor', text: 'Yetkazib berish juda tez. Har safar kutganimdan ham yaxshi natija olaman.', rating: 5, img: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100' },
    { name: 'Farhod T.', role: 'Talaba', text: 'Narxlari juda hamyonbop. Sifati esa juda yuqori!', rating: 4, img: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100' },
  ];

  useEffect(() => {
    const brand = searchParams.get('brand');
    const name = searchParams.get('name');
    setSelectedBrand(brand || '');
    setSearchQuery(name || '');

    const params = {};
    if (brand) params.brand = brand;
    if (name) params.name = name;

    products.getAll(params).then(res => {
      setProductsList(res.data);
      const uniqueBrands = [...new Set(res.data.map(p => p.brand))];
      setBrands(uniqueBrands);
    });
  }, [searchParams]);

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero" style={{ background: 'white', minHeight: '90vh', display: 'flex', alignItems: 'center', position: 'relative', overflow: 'hidden', padding: '60px 0' }}>
        {/* Background Decorative Elements */}
        <div style={{ position: 'absolute', top: '-10%', right: '-5%', width: 'min(600px, 100vw)', height: 'min(600px, 100vw)', background: 'radial-gradient(circle, rgba(37, 99, 235, 0.08) 0%, transparent 70%)', zIndex: 0 }}></div>
        <div style={{ position: 'absolute', bottom: '10%', left: '5%', width: '300px', height: '300px', background: 'radial-gradient(circle, rgba(124, 58, 237, 0.05) 0%, transparent 70%)', zIndex: 0 }}></div>

        <div className="container">
          <div className="hero-grid" style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
            alignItems: 'center', 
            gap: '40px',
            position: 'relative',
            zIndex: 1,
            justifyContent: 'center'
          }}>
            <motion.div 
              className="hero-content"
              initial={{ opacity: 0, x: -60 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 1, ease: "easeOut" }}
            >
              <motion.span 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 }}
                style={{ 
                  display: 'inline-block', padding: '8px 16px', borderRadius: '100px', background: 'rgba(37, 99, 235, 0.1)', 
                  color: 'var(--primary)', fontWeight: 600, fontSize: '14px', marginBottom: '24px' 
                }}
              >
                ✨ ShopSRY Premium Selection 2026
              </motion.span>
              <h1 style={{ marginBottom: '24px', fontWeight: 800 }}>
                {t('hero_title').split(' ').map((word, i) => i === 1 ? <span key={i} className="text-gradient font-extrabold">{word} </span> : word + ' ')}
              </h1>
              <p style={{ fontSize: '1.2rem', color: '#6B7280', marginBottom: '32px', lineHeight: 1.6, maxWidth: '540px' }} className="hero-desc">
                {t('hero_desc')}
              </p>
              <form 
                className="hero-search" 
                onSubmit={(e) => {
                  e.preventDefault();
                  if (searchQuery.trim()) {
                    setSearchParams({ name: searchQuery });
                    navigate(`/products?name=${searchQuery}`);
                  }
                }}
                style={{ 
                  margin: '0 0 40px 0',
                  maxWidth: '540px',
                  display: 'flex',
                  gap: '12px',
                  position: 'relative'
                }}
              >
                <div style={{ position: 'relative', flex: 1 }}>
                  <Search 
                    size={22} 
                    style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: '#86868b' }} 
                  />
                  <input 
                    type="text" 
                    placeholder={t('hero_search_placeholder')} 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    style={{ 
                      width: '100%', 
                      padding: '18px 24px 18px 52px', 
                      borderRadius: '16px', 
                      border: '2.5px solid #eee', 
                      fontSize: '18px',
                      background: 'white',
                      boxShadow: '0 4px 12px rgba(0,0,0,0.03)',
                      outline: 'none',
                      transition: '0.3s'
                    }}
                    className="hero-search-input"
                  />
                </div>
                <button 
                  type="submit" 
                  className="btn-wow" 
                  style={{ padding: '0 32px', height: 'auto', flexShrink: 0 }}
                >
                  {t('hero_search_btn')}
                </button>
              </form>

              <div className="hero-btns" style={{ display: 'flex', gap: '20px', alignItems: 'center', flexWrap: 'wrap' }}>
                <Link to="/products" className="btn-secondary" style={{ padding: '16px 32px', borderRadius: '16px' }}>
                  {t('hero_catalog_btn')} <ArrowRight size={20} />
                </Link>
                <div className="glass" style={{ padding: '8px 24px', borderRadius: '16px', display: 'flex', alignItems: 'center', gap: '12px', border: '1px solid #eee' }}>
                  <div style={{ display: 'flex' }}>
                     {[1,2,3].map(i => <div key={i} style={{ width: '32px', height: '32px', borderRadius: '50%', border: '2px solid white', marginLeft: i > 1 ? '-12px' : 0, background: '#eee' }}></div>)}
                  </div>
                  <span style={{ fontSize: '14px', fontWeight: 600 }}>{t('hero_customers')}</span>
                </div>
              </div>
            </motion.div>

            <motion.div 
              className="hero-image floating-anim"
              initial={{ opacity: 0, scale: 0.8, x: 60 }}
              animate={{ opacity: 1, scale: 1, x: 0 }}
              transition={{ duration: 1.2, ease: "easeOut" }}
              style={{ position: 'relative', display: 'flex', justifyContent: 'center' }}
            >
              <div style={{ 
                position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', 
                width: '100%', height: '100%', background: 'radial-gradient(circle, rgba(37, 99, 235, 0.05) 0%, transparent 70%)',
                zIndex: -1
              }}></div>
              <img 
                src="/hero-image.png" 
                alt="Premium Hero" 
                style={{ width: '100%', maxWidth: '500px', filter: 'drop-shadow(0 30px 60px rgba(0,0,0,0.12))' }}
              />
              {/* Float Badge */}
              <motion.div 
                 className="glass hide-mobile"
                 animate={{ y: [0, -10, 0] }}
                 transition={{ duration: 4, repeat: Infinity }}
                 style={{ 
                   position: 'absolute', bottom: '10%', left: '-5%', padding: '16px', borderRadius: '24px', 
                   boxShadow: '0 10px 30px rgba(0,0,0,0.05)', display: 'flex', gap: '12px', alignItems: 'center' 
                 }}
              >
                <div style={{ width: '40px', height: '40px', borderRadius: '10px', background: 'var(--secondary)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white' }}>
                   <Star size={20} fill="white" />
                </div>
                <div>
                   <h4 style={{ margin: 0, fontSize: '14px' }}>{t('hero_rating')}</h4>
                   <p style={{ margin: 0, fontSize: '11px', color: '#6B7280' }}>{t('hero_quality')}</p>
                </div>
              </motion.div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Categories Grid */}
      <section id="categories" className="container section">
        <div style={{ textAlign: 'center', marginBottom: '48px' }}>
          <h4 style={{ color: '#2563EB', fontWeight: 600, letterSpacing: '1px', marginBottom: '12px' }}>{t('cat_title')}</h4>
          <h2 className="section-title" style={{ textAlign: 'center' }}>{t('cat_subtitle')}</h2>
        </div>
        <div className="category-grid">
          {categoryTiles.map((cat, i) => (
            <motion.div
              key={i}
              className="category-card"
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1 }}
            >
              <div className="category-icon" style={{ backgroundColor: cat.color }}>
                {cat.icon}
              </div>
              <h4 style={{ fontWeight: 600 }}>{cat.name}</h4>
              <Link to={`/products?category=${cat.name}`} style={{ fontSize: '12px', color: '#6B7280', marginTop: '8px', display: 'block' }}>{t('view_more')}</Link>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Dynamic Category Sections */}
      {(() => {
        const categoriesMap = productsList.reduce((acc, product) => {
          const cat = product.category || 'Boshqa';
          if (!acc[cat]) acc[cat] = [];
          acc[cat].push(product);
          return acc;
        }, {});

        return Object.entries(categoriesMap).map(([categoryName, products], index) => (
          <section key={categoryName} className="container section" style={{ paddingTop: index === 0 ? '40px' : '80px' }}>
            <div className="category-section-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '32px' }}>
              <div>
                <h4 style={{ color: '#2563EB', fontWeight: 600, letterSpacing: '1.5px', marginBottom: '8px', textTransform: 'uppercase', fontSize: '13px' }}>
                  {t('new_arrival')}
                </h4>
                <h2 className="section-title" style={{ margin: 0, fontSize: '32px' }}>{categoryName}</h2>
              </div>
              <Link 
                to={`/products?category=${categoryName}`} 
                style={{ color: '#2563EB', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '8px', fontSize: '15px' }}
              >
                {t('view_all')} <ArrowRight size={16} />
              </Link>
            </div>

            <div className="products-grid" style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', 
              gap: '20px' 
            }}>
              {products.slice(0, 8).map((product) => (
                <ProductCard key={product.id} product={product} />
              ))}
            </div>
          </section>
        ));
      })()}

      {/* Special Offer Section */}
      <section className="container section">
        <motion.div 
          className="special-offer"
          initial={{ opacity: 0, scale: 0.95 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
        >
          <div className="offer-content">
            <h4 style={{ color: '#F59E0B', fontWeight: 700, marginBottom: '16px' }}>{t('offer_subtitle')}</h4>
            <h2 style={{ fontSize: '42px', marginBottom: '24px' }}>{t('offer_title')}</h2>
            <p style={{ opacity: 0.8, marginBottom: '32px' }}>
              {t('offer_desc')}
            </p>
            <div className="timer">
              <div className="time-box"><span>12</span><p>{t('hours')}</p></div>
              <div className="time-box"><span>45</span><p>{t('mins')}</p></div>
              <div className="time-box"><span>30</span><p>{t('secs')}</p></div>
            </div>
            <Link to="/products" className="btn btn-primary" style={{ background: '#F59E0B' }}>
              {t('offer_btn')}
            </Link>
          </div>
          <div className="offer-image" style={{ flex: 1, textAlign: 'center' }}>
            <img 
              src="https://images.unsplash.com/photo-1491933382434-500287f9b54b?w=600" 
              alt="Offer product" 
              style={{ width: '100%', borderRadius: '20px', boxShadow: '0 20px 40px rgba(0,0,0,0.4)' }}
            />
          </div>
        </motion.div>
      </section>

      {/* Reviews Section */}
      <section id="about" className="container section">
        <div style={{ textAlign: 'center', marginBottom: '60px' }}>
          <h4 style={{ color: '#2563EB', fontWeight: 600, letterSpacing: '1px', marginBottom: '12px' }}>{t('reviews_title')}</h4>
          <h2 className="section-title">{t('reviews_subtitle')}</h2>
        </div>
        <div className="reviews-grid">
          {reviews.map((review, i) => (
            <motion.div 
              key={i} 
              className="review-card"
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1 }}
            >
              <div style={{ color: '#F59E0B', marginBottom: '16px' }}>
                <Quote size={32} />
              </div>
              <p style={{ fontStyle: 'italic', color: '#4B5563', marginBottom: '24px', minHeight: '80px' }}>
                "{review.text}"
              </p>
              <div className="review-header">
                <img src={review.img} alt={review.name} className="reviewer-img" />
                <div className="reviewer-info">
                  <h4>{review.name}</h4>
                  <p>{review.role}</p>
                  <div style={{ display: 'flex', gap: '2px', marginTop: '4px' }}>
                    {[1, 2, 3, 4, 5].map(star => (
                      <Star key={star} size={12} fill={star <= review.rating ? "#F59E0B" : "none"} color={star <= review.rating ? "#F59E0B" : "#D1D5DB"} />
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Newsletter Section */}
      <section id="contact" className="container section">
        <motion.div 
          className="newsletter"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          transition={{ duration: 1 }}
        >
          <h2 style={{ fontSize: '32px', marginBottom: '16px' }}>{t('newsletter_title')}</h2>
          <p style={{ opacity: 0.8 }}>{t('newsletter_desc')}</p>
          <form className="newsletter-form" onSubmit={(e) => e.preventDefault()}>
            <input type="email" placeholder={t('newsletter_placeholder')} required />
            <button type="submit" className="btn btn-primary" style={{ background: '#111827' }}>{t('newsletter_btn')}</button>
          </form>
        </motion.div>
      </section>
    </div>
  );
};

export default Home;
